#include "core_internal.h"
#include "bigint.h"
#include "sloph/context.h"

#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef enum { VALUE_INT, VALUE_BYTES, VALUE_CON, VALUE_CLOSURE } ValueKind;
typedef struct Value Value;
typedef struct { const char **names; Value **values; size_t count; } ValueEnv;
struct Value {
    ValueKind kind;
    union {
        SlophBigInt integer;
        struct { const unsigned char *data; size_t length; bool owned; } bytes;
        struct { const char *constructor; Value **fields; size_t count, depth; } con;
        struct { SlophCoreBinder *binder; SlophCoreExpr *body; ValueEnv env; } closure;
    } as;
};
typedef struct {
    SlophContext *ctx; SlophCoreUnit *unit; const SlophLimits *limits;
    size_t fuel, nodes, depth;
    Value **allocated; size_t allocated_count, allocated_cap;
    Value **cache; unsigned char *cached;
} Machine;

static SlophSpan esp(SlophCoreSpan s){SlophSpan r={s.start,s.end};return r;}
static SlophStatus efail(Machine*m,const char*code,const char*message,SlophCoreSpan s){SlophStatus r=sloph_context_add_diagnostic(m->ctx,code,"eval",message,esp(s));return r==SLOPH_STATUS_OK?SLOPH_STATUS_INVALID_ARGUMENT:r;}
static SlophStatus efail_details(Machine*m,const char*code,const char*message,const char*details,SlophCoreSpan s){SlophStatus r=sloph_context_add_diagnostic_full(m->ctx,code,"eval",message,details,esp(s),SLOPH_SEVERITY_ERROR);return r==SLOPH_STATUS_OK?SLOPH_STATUS_INVALID_ARGUMENT:r;}
static SlophStatus limit(Machine*m,const char*name,SlophCoreSpan s){char message[160],details[160];size_t configured=!strcmp(name,"fuel")?m->limits->fuel:!strcmp(name,"integer_bits")?m->limits->integer_bits:!strcmp(name,"value_nodes")?m->limits->value_nodes:!strcmp(name,"output_bytes")?m->limits->output_bytes:m->limits->evaluation_depth;(void)snprintf(message,sizeof(message),"%s limit exceeded (configured %zu)",name,configured);(void)snprintf(details,sizeof(details),"{\"configured\":%zu,\"limit\":\"%s\"}",configured,name);return efail_details(m,"core.eval.limit_exceeded",message,details,s);}
static SlophStatus consume(Machine*m,size_t n,SlophCoreSpan s){if(n>m->fuel)return limit(m,"fuel",s);m->fuel-=n;return SLOPH_STATUS_OK;}
static SlophStatus enter(Machine*m,SlophCoreSpan s){if(++m->depth>m->limits->evaluation_depth){--m->depth;return limit(m,"evaluation_depth",s);}return SLOPH_STATUS_OK;}
static Value *env_get(ValueEnv e,const char*n){size_t i=e.count;while(i){--i;if(!strcmp(e.names[i],n))return e.values[i];}return NULL;}
static SlophStatus value_new(Machine*m,ValueKind kind,SlophCoreSpan s,Value**out){Value*v;if(++m->nodes>m->limits->value_nodes)return limit(m,"value_nodes",s);v=(Value*)calloc(1,sizeof(*v));if(!v)return SLOPH_STATUS_OUT_OF_MEMORY;v->kind=kind;if(kind==VALUE_INT)sloph_bigint_init(&v->as.integer);if(m->allocated_count==m->allocated_cap){size_t z=m->allocated_cap?m->allocated_cap*2u:64u;Value**p=(Value**)realloc(m->allocated,z*sizeof(*p));if(!p){free(v);return SLOPH_STATUS_OUT_OF_MEMORY;}m->allocated=p;m->allocated_cap=z;}m->allocated[m->allocated_count++]=v;*out=v;return SLOPH_STATUS_OK;}
static SlophStatus eval(Machine*,SlophCoreExpr*,ValueEnv,Value**);
static SlophStatus eval_primitive(Machine*m,SlophCoreExpr*x,ValueEnv env,Value**out){
    Value **args;size_t i;SlophStatus r;const char*n=x->as.prim.name;
    args=(Value**)calloc(x->as.prim.count,sizeof(*args));if(x->as.prim.count&&!args)return SLOPH_STATUS_OUT_OF_MEMORY;
    for(i=0;i<x->as.prim.count;++i)if((r=eval(m,x->as.prim.items[i],env,&args[i]))!=SLOPH_STATUS_OK){free(args);return r;}
    if(!strncmp(n,"foreign.",8)||!strcmp(n,"runtime.trap")){free(args);return efail(m,"core.eval.effectful_primitive","the pure reference evaluator cannot execute an effectful primitive",x->span);}
    if(!strcmp(n,"bytes.length")){char text[32];int z;if(args[0]->kind!=VALUE_BYTES){free(args);return efail(m,"core.eval.primitive_value","bytes.length received a non-Bytes value",x->span);}if((r=consume(m,1,x->span))!=SLOPH_STATUS_OK){free(args);return r;}z=snprintf(text,sizeof(text),"%zu",args[0]->as.bytes.length);if(z<0||(size_t)z>=sizeof(text)){free(args);return SLOPH_STATUS_INTERNAL_ERROR;}r=value_new(m,VALUE_INT,x->span,out);if(r==SLOPH_STATUS_OK&&!sloph_bigint_parse_decimal(&(*out)->as.integer,text,(size_t)z,m->limits->integer_bits))r=limit(m,"integer_bits",x->span);free(args);return r;}
    if(!strcmp(n,"int.to_bytes")){char*text;size_t length;if(args[0]->kind!=VALUE_INT){free(args);return efail(m,"core.eval.primitive_value","int.to_bytes received a non-integer",x->span);}if(!sloph_bigint_decimal(&args[0]->as.integer,&text,&length)){free(args);return SLOPH_STATUS_OUT_OF_MEMORY;}r=consume(m,1u+sloph_bigint_u64_limbs(&args[0]->as.integer)+length,x->span);if(r==SLOPH_STATUS_OK)r=value_new(m,VALUE_BYTES,x->span,out);if(r==SLOPH_STATUS_OK){unsigned char*copy=(unsigned char*)malloc(length?length:1u);if(!copy)r=SLOPH_STATUS_OUT_OF_MEMORY;else{memcpy(copy,text,length);(*out)->as.bytes.data=copy;(*out)->as.bytes.length=length;(*out)->as.bytes.owned=true;}}free(text);free(args);return r;}
    if(args[0]->kind!=VALUE_INT||args[1]->kind!=VALUE_INT){free(args);return efail(m,"core.eval.primitive_value","integer primitive received a non-integer",x->span);}
    {size_t l=sloph_bigint_u64_limbs(&args[0]->as.integer),q=sloph_bigint_u64_limbs(&args[1]->as.integer);if(!strcmp(n,"int.equal")||!strcmp(n,"int.less")){bool truth=!strcmp(n,"int.equal")?sloph_bigint_compare(&args[0]->as.integer,&args[1]->as.integer)==0:sloph_bigint_compare(&args[0]->as.integer,&args[1]->as.integer)<0;r=consume(m,1u+l+q,x->span);if(r==SLOPH_STATUS_OK)r=value_new(m,VALUE_CON,x->span,out);if(r==SLOPH_STATUS_OK){(*out)->as.con.constructor=truth?"sloph::Bool::True":"sloph::Bool::False";(*out)->as.con.depth=1u;}free(args);return r;}r=consume(m,1u+(!strcmp(n,"int.mul")?l*q:l+q),x->span);if(r!=SLOPH_STATUS_OK){free(args);return r;}r=value_new(m,VALUE_INT,x->span,out);if(r==SLOPH_STATUS_OK){bool ok=!strcmp(n,"int.add")?sloph_bigint_add(&(*out)->as.integer,&args[0]->as.integer,&args[1]->as.integer,m->limits->integer_bits):!strcmp(n,"int.sub")?sloph_bigint_subtract(&(*out)->as.integer,&args[0]->as.integer,&args[1]->as.integer,m->limits->integer_bits):!strcmp(n,"int.mul")?sloph_bigint_multiply(&(*out)->as.integer,&args[0]->as.integer,&args[1]->as.integer,m->limits->integer_bits):false;if(!ok)r=!strcmp(n,"int.add")||!strcmp(n,"int.sub")||!strcmp(n,"int.mul")?limit(m,"integer_bits",x->span):efail(m,"core.eval.unknown_primitive","unknown primitive",x->span);}free(args);return r;}
}
static SlophStatus eval(Machine*m,SlophCoreExpr*x,ValueEnv env,Value**out){
    SlophStatus r;size_t i;if((r=enter(m,x->span))!=SLOPH_STATUS_OK)return r;if((r=consume(m,1,x->span))!=SLOPH_STATUS_OK)goto done;
    switch(x->kind){
    case SLOPH_EXPR_INT:r=value_new(m,VALUE_INT,x->span,out);if(r==SLOPH_STATUS_OK&&!sloph_bigint_parse_decimal(&(*out)->as.integer,x->as.integer,strlen(x->as.integer),m->limits->integer_bits))r=limit(m,"integer_bits",x->span);break;
    case SLOPH_EXPR_BYTES:r=consume(m,1u+x->as.bytes.length,x->span);if(r==SLOPH_STATUS_OK)r=value_new(m,VALUE_BYTES,x->span,out);if(r==SLOPH_STATUS_OK){(*out)->as.bytes.data=x->as.bytes.data;(*out)->as.bytes.length=x->as.bytes.length;}break;
    case SLOPH_EXPR_LOCAL:*out=env_get(env,x->as.name);r=*out?SLOPH_STATUS_OK:efail(m,"core.eval.expression_form","validated local was unavailable",x->span);break;
    case SLOPH_EXPR_GLOBAL:{size_t d;for(d=0;d<m->unit->definition_count;++d)if(!strcmp(m->unit->definitions[d].name,x->as.name))break;if(d==m->unit->definition_count){r=efail(m,"core.eval.unknown_symbol","unknown evaluation symbol",x->span);break;}if(m->cached[d]){*out=m->cache[d];r=SLOPH_STATUS_OK;}else{ValueEnv empty={0};r=consume(m,1,x->span);if(r==SLOPH_STATUS_OK)r=eval(m,m->unit->definitions[d].value,empty,out);if(r==SLOPH_STATUS_OK){m->cache[d]=*out;m->cached[d]=1;}}break;}
    case SLOPH_EXPR_TYPE:r=efail(m,"core.eval.type_expression","a type argument cannot be evaluated directly",x->span);break;
    case SLOPH_EXPR_LAM:if(x->as.lam.binder.is_type)r=eval(m,x->as.lam.body,env,out);else{r=value_new(m,VALUE_CLOSURE,x->span,out);if(r==SLOPH_STATUS_OK){Value*v=*out;v->as.closure.binder=&x->as.lam.binder;v->as.closure.body=x->as.lam.body;v->as.closure.env.count=env.count;if(env.count){v->as.closure.env.names=(const char**)malloc(env.count*sizeof(*v->as.closure.env.names));v->as.closure.env.values=(Value**)malloc(env.count*sizeof(*v->as.closure.env.values));if(!v->as.closure.env.names||!v->as.closure.env.values)r=SLOPH_STATUS_OUT_OF_MEMORY;else{memcpy(v->as.closure.env.names,env.names,env.count*sizeof(*env.names));memcpy(v->as.closure.env.values,env.values,env.count*sizeof(*env.values));}}}}break;
    case SLOPH_EXPR_APP:{Value*f,*arg;if(x->as.app.argument->kind==SLOPH_EXPR_TYPE){r=eval(m,x->as.app.function,env,out);break;}r=eval(m,x->as.app.function,env,&f);if(r!=SLOPH_STATUS_OK)break;if(f->kind!=VALUE_CLOSURE){r=efail(m,"core.eval.not_function","application target did not evaluate to a closure",x->span);break;}r=eval(m,x->as.app.argument,env,&arg);if(r==SLOPH_STATUS_OK){size_t z=f->as.closure.env.count;const char**ns=(const char**)malloc((z+1)*sizeof(*ns));Value**vs=(Value**)malloc((z+1)*sizeof(*vs));ValueEnv ne;if(!ns||!vs){free(ns);free(vs);r=SLOPH_STATUS_OUT_OF_MEMORY;break;}if(z){memcpy(ns,f->as.closure.env.names,z*sizeof(*ns));memcpy(vs,f->as.closure.env.values,z*sizeof(*vs));}ns[z]=f->as.closure.binder->name;vs[z]=arg;ne=(ValueEnv){ns,vs,z+1};r=eval(m,f->as.closure.body,ne,out);free(ns);free(vs);}break;}
    case SLOPH_EXPR_LET:{Value*v;const char**ns;Value**vs;ValueEnv ne;r=eval(m,x->as.let.value,env,&v);if(r!=SLOPH_STATUS_OK)break;ns=(const char**)malloc((env.count+1)*sizeof(*ns));vs=(Value**)malloc((env.count+1)*sizeof(*vs));if(!ns||!vs){free(ns);free(vs);r=SLOPH_STATUS_OUT_OF_MEMORY;break;}if(env.count){memcpy(ns,env.names,env.count*sizeof(*ns));memcpy(vs,env.values,env.count*sizeof(*vs));}ns[env.count]=x->as.let.binder.name;vs[env.count]=v;ne=(ValueEnv){ns,vs,env.count+1};r=eval(m,x->as.let.body,ne,out);free(ns);free(vs);break;}
    case SLOPH_EXPR_PRIM:r=eval_primitive(m,x,env,out);break;
    case SLOPH_EXPR_CON:{Value*v;r=value_new(m,VALUE_CON,x->span,&v);if(r!=SLOPH_STATUS_OK)break;v->as.con.constructor=x->as.con.constructor;v->as.con.count=x->as.con.field_count;v->as.con.depth=1;if(v->as.con.count){v->as.con.fields=(Value**)calloc(v->as.con.count,sizeof(*v->as.con.fields));if(!v->as.con.fields){r=SLOPH_STATUS_OUT_OF_MEMORY;break;}}for(i=0;i<v->as.con.count;++i){r=eval(m,x->as.con.fields[i],env,&v->as.con.fields[i]);if(r!=SLOPH_STATUS_OK)break;if(v->as.con.fields[i]->kind==VALUE_CON&&v->as.con.depth<=v->as.con.fields[i]->as.con.depth)v->as.con.depth=v->as.con.fields[i]->as.con.depth+1;}if(r==SLOPH_STATUS_OK&&v->as.con.depth>m->limits->evaluation_depth)r=limit(m,"value_depth",x->span);*out=v;break;}
    case SLOPH_EXPR_CASE:{Value*v;r=eval(m,x->as.case_.scrutinee,env,&v);if(r!=SLOPH_STATUS_OK)break;if(v->kind!=VALUE_CON){r=efail(m,"core.eval.case_value","case scrutinee did not evaluate to constructor data",x->span);break;}for(i=0;i<x->as.case_.alternative_count;++i)if(!strcmp(x->as.case_.alternatives[i].constructor,v->as.con.constructor))break;if(i==x->as.case_.alternative_count){r=efail(m,"core.eval.case_value","constructor had no case alternative",x->span);break;}{SlophCoreAlternative*a=&x->as.case_.alternatives[i];size_t z=env.count;const char**ns=(const char**)malloc((z+a->binder_count)*sizeof(*ns));Value**vs=(Value**)malloc((z+a->binder_count)*sizeof(*vs));ValueEnv ne;if((z+a->binder_count)&&(!ns||!vs)){free(ns);free(vs);r=SLOPH_STATUS_OUT_OF_MEMORY;break;}if(z){memcpy(ns,env.names,z*sizeof(*ns));memcpy(vs,env.values,z*sizeof(*vs));}for(i=0;i<a->binder_count;++i){ns[z+i]=a->binders[i].name;vs[z+i]=v->as.con.fields[i];}ne=(ValueEnv){ns,vs,z+a->binder_count};r=eval(m,a->body,ne,out);free(ns);free(vs);}break;}
    default:r=efail(m,"core.eval.expression_form","unsupported expression representation",x->span);break;
    }
done:--m->depth;return r;
}
typedef struct { char*data;size_t length,capacity,max;Machine*m; } Output;
static SlophStatus append(Output*o,const char*s,size_t n){char*p;if(n>o->max-o->length)return limit(o->m,"output_bytes",(SlophCoreSpan){0,0});if(o->length+n+1>o->capacity){size_t z=o->capacity?o->capacity*2:128;while(z<o->length+n+1)z*=2;p=(char*)realloc(o->data,z);if(!p)return SLOPH_STATUS_OUT_OF_MEMORY;o->data=p;o->capacity=z;}memcpy(o->data+o->length,s,n);o->length+=n;o->data[o->length]=0;return SLOPH_STATUS_OK;}
static SlophStatus format(Output*o,Value*v,size_t depth){SlophStatus r;size_t i;char*decimal;size_t n;static const char hex[]="0123456789abcdef";if(depth>o->m->limits->evaluation_depth)return limit(o->m,"evaluation_depth",(SlophCoreSpan){0,0});switch(v->kind){case VALUE_INT:if(!sloph_bigint_decimal(&v->as.integer,&decimal,&n))return SLOPH_STATUS_OUT_OF_MEMORY;r=append(o,"(int ",5);if(r==SLOPH_STATUS_OK)r=append(o,decimal,n);if(r==SLOPH_STATUS_OK)r=append(o,")",1);free(decimal);return r;case VALUE_BYTES:r=append(o,"(bytes x",8);for(i=0;r==SLOPH_STATUS_OK&&i<v->as.bytes.length;++i){char pair[2]={hex[v->as.bytes.data[i]>>4],hex[v->as.bytes.data[i]&15]};r=append(o,pair,2);}return r==SLOPH_STATUS_OK?append(o,")",1):r;case VALUE_CON:r=append(o,"(con ",5);if(r==SLOPH_STATUS_OK)r=append(o,v->as.con.constructor,strlen(v->as.con.constructor));for(i=0;r==SLOPH_STATUS_OK&&i<v->as.con.count;++i){r=append(o," ",1);if(r==SLOPH_STATUS_OK)r=format(o,v->as.con.fields[i],depth+1);}return r==SLOPH_STATUS_OK?append(o,")",1):r;case VALUE_CLOSURE:return efail(o->m,"core.eval.non_printable_result","function values are not printable Core v0 data",(SlophCoreSpan){0,0});}return SLOPH_STATUS_INTERNAL_ERROR;}
SlophStatus sloph_core_evaluate(SlophContext*ctx,SlophCoreUnit*unit,const char*symbol,char**text,size_t*length){Machine m={0};Value*v=NULL;Output o={0};SlophStatus r;size_t i,d;char details[512],message[768];if(!ctx||!unit||!symbol||!text||!length)return SLOPH_STATUS_INVALID_ARGUMENT;*text=NULL;*length=0;if((r=sloph_core_validate(ctx,unit))!=SLOPH_STATUS_OK)return r;m.ctx=ctx;m.unit=unit;m.limits=sloph_context_limits(ctx);m.fuel=m.limits->fuel;m.cache=(Value**)calloc(unit->definition_count,sizeof(*m.cache));m.cached=(unsigned char*)calloc(unit->definition_count,1);if((unit->definition_count)&&(!m.cache||!m.cached)){r=SLOPH_STATUS_OUT_OF_MEMORY;goto done;}for(d=0;d<unit->definition_count;++d)if(!strcmp(unit->definitions[d].name,symbol))break;if(d==unit->definition_count){(void)snprintf(message,sizeof(message),"unknown evaluation symbol '%s'",symbol);(void)snprintf(details,sizeof(details),"{\"symbol\":\"%s\"}",symbol);r=efail_details(&m,"core.eval.unknown_symbol",message,details,unit->span);goto done;}{SlophCoreExpr global={0};global.kind=SLOPH_EXPR_GLOBAL;global.span=unit->definitions[d].span;global.as.name=(char*)symbol;r=eval(&m,&global,(ValueEnv){0},&v);}if(r!=SLOPH_STATUS_OK)goto done;if(v->kind==VALUE_CLOSURE){(void)snprintf(details,sizeof(details),"{\"symbol\":\"%s\"}",symbol);r=efail_details(&m,"core.eval.non_printable_result","the selected symbol evaluates to a function",details,unit->span);goto done;}o.m=&m;o.max=m.limits->output_bytes;r=append(&o,"(value 0 ",9);if(r==SLOPH_STATUS_OK)r=format(&o,v,1);if(r==SLOPH_STATUS_OK)r=append(&o,")\n",2);if(r==SLOPH_STATUS_OK){*text=o.data;*length=o.length;o.data=NULL;}
done:free(o.data);for(i=0;i<m.allocated_count;++i){Value*q=m.allocated[i];if(q->kind==VALUE_INT)sloph_bigint_destroy(&q->as.integer);else if(q->kind==VALUE_BYTES&&q->as.bytes.owned)free((void*)q->as.bytes.data);else if(q->kind==VALUE_CON)free(q->as.con.fields);else if(q->kind==VALUE_CLOSURE){free(q->as.closure.env.names);free(q->as.closure.env.values);}free(q);}free(m.allocated);free(m.cache);free(m.cached);return r;}
